import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.CRbjHCyB.js";const m=JSON.parse('{"title":"Fake Compilation","description":"","frontmatter":{},"headers":[],"relativePath":"catter/features/fake-compilation.md","filePath":"en/catter/features/fake-compilation.md"}'),n={name:"catter/features/fake-compilation.md"};function l(s,e,r,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="fake-compilation" tabindex="-1">Fake Compilation <a class="header-anchor" href="#fake-compilation" aria-label="Permalink to &quot;Fake Compilation&quot;">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>This feature is planned but not yet implemented.</p></div><h2 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h2><p>Instead of forwarding compilation to the real compiler, catter generates fake placeholder <code>.o</code> files. This lets the build system complete its full run -- including link steps -- without actual compilation.</p><p>The result:</p><ul><li><strong>A complete CDB in a fraction of the time.</strong> No real compilation work is performed, so the build finishes as fast as the build system can schedule it.</li><li><strong>Full linker command capture.</strong> Because placeholder object files exist on disk, linker invocations proceed normally and can be intercepted.</li></ul><h2 id="smart-dependency-analysis" tabindex="-1">Smart Dependency Analysis <a class="header-anchor" href="#smart-dependency-analysis" aria-label="Permalink to &quot;Smart Dependency Analysis&quot;">​</a></h2><p>Not all commands can be faked. Code generators -- such as LLVM TableGen -- must still be built genuinely, because they produce headers that other compilations depend on.</p><p>Catter will analyze dependencies to distinguish between:</p><ul><li><strong>Regular compilation</strong> -- Can be faked. The output <code>.o</code> file is only consumed by the linker.</li><li><strong>Code generators</strong> -- Must be built. Their output (generated headers, source files) is needed as input by other compilation steps.</li></ul><p>This achieves a &quot;minimal build&quot;: only build what is strictly necessary for correct CDB generation and header production, and fake everything else.</p>',11)])])}const h=t(n,[["render",l]]);export{m as __pageData,h as default};
